import{_ as e,c as o,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Plataformas: Verificação de Cota de IA | opencode-mystatus","description":"Aprenda a verificar cotas de IA em OpenAI, Zhipu AI, GitHub Copilot e Google Cloud. Guia completo com detalhes de cada plataforma suportada pelo opencode-mystatus.","frontmatter":{"title":"Plataformas: Verificação de Cota de IA | opencode-mystatus","sidebarTitle":"Plataformas","subtitle":"Plataformas: Verificação de Cota de IA","description":"Aprenda a verificar cotas de IA em OpenAI, Zhipu AI, GitHub Copilot e Google Cloud. Guia completo com detalhes de cada plataforma suportada pelo opencode-mystatus.","order":2},"headers":[],"relativePath":"pt/vbgate/opencode-mystatus/platforms/index.md","filePath":"pt/vbgate/opencode-mystatus/platforms/index.md"}'),d={name:"pt/vbgate/opencode-mystatus/platforms/index.md"};function r(l,a,s,n,p,u){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="funcionalidades-da-plataforma" tabindex="-1">Funcionalidades da Plataforma <a class="header-anchor" href="#funcionalidades-da-plataforma" aria-label="Permalink to &quot;Funcionalidades da Plataforma&quot;">​</a></h1><p>Este capítulo apresenta detalhadamente as funcionalidades de verificação de cota das várias plataformas de IA suportadas pelo opencode-mystatus.</p><h2 id="plataformas-suportadas" tabindex="-1">Plataformas Suportadas <a class="header-anchor" href="#plataformas-suportadas" aria-label="Permalink to &quot;Plataformas Suportadas&quot;">​</a></h2><p>O opencode-mystatus suporta as seguintes 4 plataformas principais de IA:</p><table tabindex="0"><thead><tr><th>Plataforma</th><th>Tipo de Cota</th><th>Características</th></tr></thead><tbody><tr><td>OpenAI</td><td>Janela de 3 horas / 24 horas</td><td>Suporta assinaturas Plus, Team, Pro</td></tr><tr><td>Zhipu AI</td><td>Cota de 5 horas Token / Cota mensal MCP</td><td>Suporta Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>Cota mensal</td><td>Exibe uso de Premium Requests</td></tr><tr><td>Google Cloud</td><td>Calculado por modelo</td><td>Suporta múltiplas contas, 4 modelos</td></tr></tbody></table><h2 id="detalhes-da-plataforma" tabindex="-1">Detalhes da Plataforma <a class="header-anchor" href="#detalhes-da-plataforma" aria-label="Permalink to &quot;Detalhes da Plataforma&quot;">​</a></h2><h3 id="cota-do-openai" tabindex="-1"><a href="./openai-usage/">Cota do OpenAI</a> <a class="header-anchor" href="#cota-do-openai" aria-label="Permalink to &quot;[Cota do OpenAI](./openai-usage/)&quot;">​</a></h3><p>Aprofunde-se no mecanismo de verificação de cota do OpenAI:</p><ul><li>Diferença entre janelas de 3 horas e 24 horas</li><li>Mecanismo de compartilhamento de cota de conta de equipe</li><li>Análise do Token JWT para obter informações da conta</li></ul><h3 id="cota-do-zhipu-ai" tabindex="-1"><a href="./zhipu-usage/">Cota do Zhipu AI</a> <a class="header-anchor" href="#cota-do-zhipu-ai" aria-label="Permalink to &quot;[Cota do Zhipu AI](./zhipu-usage/)&quot;">​</a></h3><p>Entenda a verificação de cota do Zhipu AI e Z.ai:</p><ul><li>Método de cálculo da cota de 5 horas Token</li><li>Uso da cota mensal MCP</li><li>Exibição de API Key mascarada</li></ul><h3 id="cota-do-github-copilot" tabindex="-1"><a href="./copilot-usage/">Cota do GitHub Copilot</a> <a class="header-anchor" href="#cota-do-github-copilot" aria-label="Permalink to &quot;[Cota do GitHub Copilot](./copilot-usage/)&quot;">​</a></h3><p>Domine o gerenciamento de cota do GitHub Copilot:</p><ul><li>Significado de Premium Requests</li><li>Diferenças de cota entre diferentes tipos de assinatura</li><li>Cálculo do tempo de reinicialização mensal</li></ul><h3 id="cota-do-google-cloud" tabindex="-1"><a href="./google-usage/">Cota do Google Cloud</a> <a class="header-anchor" href="#cota-do-google-cloud" aria-label="Permalink to &quot;[Cota do Google Cloud](./google-usage/)&quot;">​</a></h3><p>Aprenda a verificação de cota de múltiplas contas do Google Cloud:</p><ul><li>Diferença entre 4 modelos (G3 Pro, G3 Image, G3 Flash, Claude)</li><li>Gerenciamento e alternância de múltiplas contas</li><li>Mecanismo de leitura de arquivos de autenticação</li></ul><h2 id="guia-de-escolha" tabindex="-1">Guia de Escolha <a class="header-anchor" href="#guia-de-escolha" aria-label="Permalink to &quot;Guia de Escolha&quot;">​</a></h2><p>Com base nas plataformas que você usa, escolha o tutorial correspondente:</p><ul><li><strong>Usa apenas OpenAI</strong>: Veja diretamente <a href="./openai-usage/">Cota do OpenAI</a></li><li><strong>Usa apenas Zhipu AI</strong>: Veja diretamente <a href="./zhipu-usage/">Cota do Zhipu AI</a></li><li><strong>Usuário de múltiplas plataformas</strong>: Recomenda-se ler todos os tutoriais de plataformas em ordem</li><li><strong>Usuário do Google Cloud</strong>: Primeiro precisa instalar o plugin <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a></li></ul><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><p>Após completar este capítulo, você pode continuar aprendendo <a href="./../advanced/">Funcionalidades Avançadas</a>, para saber mais opções de configuração.</p>',23)])])}const h=e(d,[["render",r]]);export{m as __pageData,h as default};
